.mrg-alert {
  --mrg-alert-signal: var(--mrg-semantic-color-status-info-border);
  --mrg-alert-signal-background: var(--mrg-semantic-color-status-info-background);
  --mrg-alert-signal-foreground: var(--mrg-semantic-color-status-info-foreground);
  align-items: start;
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
  border-radius: var(--mrg-semantic-radius-status);
  box-shadow: inset 0 var(--mrg-semantic-border-width-strong) 0 var(--mrg-alert-signal);
  box-sizing: border-box;
  color: var(--mrg-semantic-color-foreground-primary);
  display: grid;
  gap: var(--mrg-semantic-space-inline-md);
  grid-template-columns: auto minmax(0, 1fr);
  inline-size: 100%;
  max-inline-size: 100%;
  min-inline-size: 0;
  padding: var(--mrg-semantic-density-panel-padding);
}

.mrg-alert[data-variant="success"] {
  --mrg-alert-signal: var(--mrg-semantic-color-status-success-border);
  --mrg-alert-signal-background: var(--mrg-semantic-color-status-success-background);
  --mrg-alert-signal-foreground: var(--mrg-semantic-color-status-success-foreground);
}

.mrg-alert[data-variant="warning"] {
  --mrg-alert-signal: var(--mrg-semantic-color-status-warning-border);
  --mrg-alert-signal-background: var(--mrg-semantic-color-status-warning-background);
  --mrg-alert-signal-foreground: var(--mrg-semantic-color-status-warning-foreground);
}

.mrg-alert[data-variant="error"] {
  --mrg-alert-signal: var(--mrg-semantic-color-status-danger-border);
  --mrg-alert-signal-background: var(--mrg-semantic-color-status-danger-background);
  --mrg-alert-signal-foreground: var(--mrg-semantic-color-status-danger-foreground);
}

.mrg-alert [data-slot="alert-icon"] {
  align-items: center;
  background: var(--mrg-alert-signal-background);
  border: var(--mrg-semantic-border-width-strong) solid var(--mrg-alert-signal);
  border-radius: var(--mrg-semantic-radius-compact);
  color: var(--mrg-alert-signal-foreground);
  display: inline-flex;
  font-weight: var(--mrg-semantic-font-weight-strong);
  inline-size: var(--mrg-semantic-size-target-minimum);
  justify-content: center;
  min-block-size: var(--mrg-semantic-size-target-minimum);
}

.mrg-alert [data-slot="alert-content"] {
  display: grid;
  gap: var(--mrg-semantic-space-stack-xs);
  min-inline-size: 0;
}

.mrg-alert [data-slot="alert-variant-label"] {
  color: var(--mrg-alert-signal-foreground);
  font-size: var(--mrg-semantic-font-size-caption);
  font-weight: var(--mrg-semantic-font-weight-strong);
}

.mrg-alert [data-slot="alert-title"] {
  font-size: var(--mrg-semantic-font-size-heading-small);
  font-weight: var(--mrg-semantic-font-weight-heading);
  letter-spacing: var(--mrg-semantic-font-letter-spacing-heading);
  line-height: var(--mrg-semantic-font-line-height-heading);
  margin: 0;
  text-wrap: balance;
}

.mrg-alert :is([data-slot="alert-description"], [data-slot="alert-body"]) {
  max-inline-size: var(--mrg-semantic-size-content-prose);
  overflow-wrap: anywhere;
  text-wrap: pretty;
}

.mrg-alert [data-slot="alert-actions"] {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: var(--mrg-semantic-space-inline-sm);
  margin-block-start: var(--mrg-semantic-space-stack-sm);
}

@media (forced-colors: active) {
  .mrg-alert {
    border-color: CanvasText;
    box-shadow: inset 0 var(--mrg-semantic-border-width-strong) 0 CanvasText;
    forced-color-adjust: auto;
  }

  .mrg-alert [data-slot="alert-icon"] {
    background: Canvas;
    border-color: CanvasText;
    color: CanvasText;
  }
}

"use client";

import {
  Fragment,
  forwardRef,
  isValidElement,
  useEffect,
  type HTMLAttributes,
  type ReactNode,
} from "react";

import { useMergoraMessage } from "../provider/index";
import { useAnnouncer } from "../sr-announcer/index";
import "./alert.css";

export type AlertVariant = "info" | "success" | "warning" | "error";
export type AlertLiveMode = "off" | "polite" | "assertive";
export type AlertHeadingLevel = 1 | 2 | 3 | 4 | 5 | 6;

interface AlertBaseProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "aria-atomic" | "aria-label" | "aria-labelledby" | "aria-live" | "children" | "role" | "title"
> {
  /** Reserved: Alert owns announcement atomicity through the shared announcer. */
  readonly "aria-atomic"?: never;
  /** Reserved: the visible title and content provide the Alert's name and context. */
  readonly "aria-label"?: never;
  /** Reserved: Alert owns the relationships for its visible heading and content. */
  readonly "aria-labelledby"?: never;
  /** Reserved: opt into announcements with `live` and `announcement` instead. */
  readonly "aria-live"?: never;
  /** Action controls rendered after the visible alert content and outside live regions. */
  readonly actions?: ReactNode;
  /** Additional visible alert body content; required when `description` is empty. */
  readonly children?: ReactNode;
  /** Concise visible explanation; required when `children` is empty. */
  readonly description?: ReactNode;
  /** Native heading level used for `title`; defaults to 2. */
  readonly headingLevel?: AlertHeadingLevel;
  /** Non-empty visible heading for the alert. */
  readonly title: ReactNode;
  /** Visual and textual severity treatment; defaults to `info`. */
  readonly variant?: AlertVariant;
  /** Localized visible override for the selected variant label. */
  readonly variantLabel?: string;
  /** Reserved: the visible Alert stays non-live while the shared announcer owns roles. */
  readonly role?: never;
}

type AlertAnnouncementPolicy =
  | {
      /** Disabled when `live` is `off`, so no announcement copy or effect is emitted. */
      readonly announcement?: never;
      /** Keeps the Alert static and non-live; this is the default mode. */
      readonly live?: "off";
    }
  | {
      /** Concise non-empty summary enqueued through the nearest shared announcer. */
      readonly announcement: string;
      /** Politeness used by the shared announcer for this summary. */
      readonly live: "assertive" | "polite";
    };

export type AlertProps = AlertBaseProps & AlertAnnouncementPolicy;

function hasContent(value: ReactNode): boolean {
  if (value === null || value === undefined || typeof value === "boolean") return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.some(hasContent);
  if (isValidElement(value) && value.type === Fragment) {
    return hasContent((value.props as { readonly children?: ReactNode }).children);
  }
  return true;
}

function assertNoAlertSemanticOverrides(props: Readonly<Record<string, unknown>>): void {
  for (const key of [
    "aria-atomic",
    "aria-label",
    "aria-labelledby",
    "aria-live",
    "role",
  ] as const) {
    if (props[key] !== undefined) {
      throw new Error(`Mergora Alert owns ${key} and does not accept a semantic override.`);
    }
  }
}

function AlertAnnouncement({
  message,
  priority,
}: {
  readonly message: string;
  readonly priority: "assertive" | "polite";
}) {
  const { announce } = useAnnouncer();
  useEffect(() => {
    announce(message, {
      dedupeKey: `alert:${priority}:${message}`,
      priority,
    });
  }, [announce, message, priority]);
  return null;
}

export const Alert = forwardRef<HTMLDivElement, AlertProps>(function Alert(props, ref) {
  assertNoAlertSemanticOverrides(props as unknown as Readonly<Record<string, unknown>>);
  const {
    actions,
    announcement,
    children,
    className,
    description,
    headingLevel = 2,
    live = "off",
    title,
    variant = "info",
    variantLabel: variantLabelProp,
    ...nativeProps
  } = props;
  if (!hasContent(title)) throw new Error("Mergora Alert requires a non-empty title.");
  if (!hasContent(description) && !hasContent(children)) {
    throw new Error("Mergora Alert requires a description or child content.");
  }
  if (variantLabelProp !== undefined && variantLabelProp.trim().length === 0) {
    throw new Error("Mergora Alert variantLabel must be non-empty when provided.");
  }
  if (live !== "off" && (announcement === undefined || announcement.trim().length === 0)) {
    throw new Error("Mergora Alert live modes require a concise non-empty announcement.");
  }
  if (live === "off" && announcement !== undefined) {
    throw new Error("Mergora Alert announcement requires polite or assertive live mode.");
  }
  const defaultVariantLabel = useMergoraMessage(
    `alert.${variant}`,
    {
      error: "Error",
      info: "Information",
      success: "Success",
      warning: "Warning",
    }[variant],
  );
  const variantLabel = variantLabelProp ?? defaultVariantLabel;
  const Heading = `h${headingLevel}` as const;

  return (
    <div
      {...nativeProps}
      className={className === undefined ? "mrg-alert" : `mrg-alert ${className}`}
      data-live={live}
      data-slot="alert"
      data-variant={variant}
      ref={ref}
    >
      {live === "off" || announcement === undefined ? null : (
        <AlertAnnouncement message={announcement.trim()} priority={live} />
      )}
      <span aria-hidden="true" data-slot="alert-icon">
        {variant === "success"
          ? "✓"
          : variant === "warning"
            ? "!"
            : variant === "error"
              ? "×"
              : "i"}
      </span>
      <div data-slot="alert-content">
        <span data-slot="alert-variant-label">{variantLabel}</span>
        <Heading data-slot="alert-title">{title}</Heading>
        {hasContent(description) ? <div data-slot="alert-description">{description}</div> : null}
        {hasContent(children) ? <div data-slot="alert-body">{children}</div> : null}
        {hasContent(actions) ? <div data-slot="alert-actions">{actions}</div> : null}
      </div>
    </div>
  );
});

Alert.displayName = "Alert";

export {
  Alert,
  type AlertHeadingLevel,
  type AlertLiveMode,
  type AlertProps,
  type AlertVariant,
} from "./alert";
